     1→/**
     2→ * AI Command Service
     3→ *
     4→ * Translates natural language into shell commands.
     5→ * Uses the existing provider router for multi-provider support.
     6→ */
     7→
     8→import { createDefaultRouter, type AIProviderRouter } from '../ai/providerRouter';
     9→import { logger } from '../logger';
    10→
    11→const log = logger.module('PhantomShell:AICommand');
    12→
    13→// System prompt for shell command generation
    14→const SYSTEM_PROMPT = `You are Phantom Shell AI, a terminal assistant for a browser-based development environment.
    15→
    16→Your job is to translate natural language requests into terminal commands.
    17→
    18→CONTEXT:
    19→- You are running in WebContainers (Node.js in browser)
    20→- Available: npm, npx, node, basic shell commands (ls, cd, cat, mkdir, rm, etc.)
    21→- NOT available: git, docker, python, system-level commands
    22→- File system is in-memory (persisted to IndexedDB)
    23→
    24→RESPONSE FORMAT:
    25→- For simple requests, respond with ONLY the command(s), one per line
    26→- For complex requests, briefly explain then provide commands
    27→- Use npm not yarn or pnpm
    28→- Prefer npx for one-off tools
    29→
    30→EXAMPLES:
    31→User: create a react app
    32→Response: npm create vite@latest my-app -- --template react
    33→
    34→User: install express
    35→Response: npm install express
    36→
    37→User: show files
    38→Response: ls -la
    39→
    40→DO NOT:
    41→- Suggest git commands (git isn't available)
    42→- Suggest python/pip commands
    43→- Output markdown formatting (just plain text)`;
    44→
    45→// ==================== TYPES ====================
    46→
    47→export interface AICommandResult {
    48→  commands: string[];
    49→  explanation?: string;
    50→  error?: string;
    51→}
    52→
    53→// ==================== SINGLETON ROUTER ====================
    54→
    55→let sharedRouter: AIProviderRouter | null = null;
    56→
    57→/**
    58→ * Get or create the shared router instance
    59→ * Uses the same router configuration as AITerminal
    60→ */
    61→export const getRouter = (): AIProviderRouter => {
    62→  if (!sharedRouter) {
    63→    sharedRouter = createDefaultRouter();
    64→  }
    65→  return sharedRouter;
    66→};
    67→
    68→/**
    69→ * Set an external router (for sharing with AITerminal)
    70→ */
    71→export const setRouter = (router: AIProviderRouter): void => {
    72→  sharedRouter = router;
    73→};
    74→
    75→// ==================== COMMAND TEMPLATES ====================
    76→
    77→/**
    78→ * Pre-defined templates for common requests (faster than AI)
    79→ */
    80→export const COMMAND_TEMPLATES: Record<string, string> = {
    81→  'create react app': 'npm create vite@latest my-app -- --template react',
    82→  'create vue app': 'npm create vite@latest my-app -- --template vue',
    83→  'create svelte app': 'npm create vite@latest my-app -- --template svelte',
    84→  'create next app': 'npx create-next-app@latest my-app',
    85→  'run dev': 'npm run dev',
    86→  'run build': 'npm run build',
    87→  'run start': 'npm start',
    88→  'run test': 'npm test',
    89→  'show files': 'ls -la',
    90→  'list files': 'ls -la',
    91→  'current directory': 'pwd',
    92→  'install dependencies': 'npm install',
    93→};
    94→
    95→/**
    96→ * Try to match a template before calling AI
    97→ */
    98→export const tryTemplate = (prompt: string): string | null => {
    99→  const lower = prompt.toLowerCase().trim();
   100→  for (const [pattern, command] of Object.entries(COMMAND_TEMPLATES)) {
   101→    if (lower.includes(pattern)) {
   102→      log.debug('Template matched', { pattern, command });
   103→      return command;
   104→    }
   105→  }
   106→  return null;
   107→};
   108→
   109→// ==================== COMMAND DETECTION ====================
   110→
   111→/**
   112→ * Check if a string looks like a shell command
   113→ */
   114→const looksLikeCommand = (str: string): boolean => {
   115→  const commandPrefixes = [
   116→    'npm ', 'npx ', 'node ', 'ls', 'cd ', 'cat ', 'mkdir ', 'rm ', 'cp ', 'mv ',
   117→    'echo ', 'touch ', 'pwd', 'head ', 'tail ', 'clear', 'exit',
   118→  ];
   119→  const lower = str.toLowerCase().trim();
   120→  return commandPrefixes.some(prefix => lower.startsWith(prefix));
   121→};
   122→
   123→// ==================== MAIN FUNCTION ====================
   124→
   125→/**
   126→ * Process an AI command request
   127→ *
   128→ * @param prompt - Natural language request from user
   129→ * @param context - Optional context (current directory, recent output)
   130→ * @returns Commands to execute and optional explanation
   131→ */
   132→export const processAICommand = async (
   133→  prompt: string,
   134→  context?: {
   135→    currentDirectory?: string;
   136→    recentOutput?: string;
   137→  }
   138→): Promise<AICommandResult> => {
   139→  // Validate input
   140→  if (!prompt.trim()) {
   141→    return {
   142→      commands: [],
   143→      error: 'Please provide a request\n(e.g., /ai create a react app)',
   144→    };
   145→  }
   146→
   147→  // Try template match first (instant response)
   148→  const templateMatch = tryTemplate(prompt);
   149→  if (templateMatch) {
   150→    log.info('Using template match', { prompt: prompt.substring(0, 50) });
   151→    return {
   152→      commands: [templateMatch],
   153→      explanation: undefined,
   154→    };
   155→  }
   156→
   157→  // Get router and check if any provider is configured
   158→  const router = getRouter();
   159→  const configuredProviders = router.getConfiguredProviders();
   160→
   161→  if (configuredProviders.length === 0) {
   162→    return {
   163→      commands: [],
   164→      error: 'No AI provider configured.\nSet up a provider in Settings.',
   165→    };
   166→  }
   167→
   168→  log.info('Processing AI command', { prompt: prompt.substring(0, 100) });
   169→
   170→  // Build context message
   171→  let contextMsg = '';
   172→  if (context?.currentDirectory) {
   173→    contextMsg += `Current directory: ${context.currentDirectory}\n`;
   174→  }
   175→  if (context?.recentOutput) {
   176→    contextMsg += `Recent terminal output:\n${context.recentOutput.slice(-500)}\n`;
   177→  }
   178→
   179→  const fullPrompt = contextMsg
   180→    ? `${contextMsg}\n---\nUser request: ${prompt}`
   181→    : prompt;
   182→
   183→  try {
   184→    // Send to AI via router
   185→    const response = await router.sendMessage({
   186→      prompt: fullPrompt,
   187→      systemPrompt: SYSTEM_PROMPT,
   188→      temperature: 0.3, // Lower temperature for more deterministic commands
   189→      maxTokens: 500, // Commands shouldn't be too long
