```typescript
// 1. Primary request attempt
const response = await primaryProvider.sendMessage(modelId, options);

// 2. If fails with retryable error (rate limit, network, quota)
// Automatically tries fallback providers in order:
DEFAULT_FALLBACK_ORDER = [
  'openrouter',    // Best flexibility
  'groq',          // Best speed
  'huggingface',   // Free fallback
  'mistral',       // European option
  'gemini',        // Google fallback
];

// 3. Returns response with metadata showing which provider was used
return {
  content: string;
  provider: string;  // Which provider actually answered
  model: string;     // Which model was used
  finishReason: 'stop' | 'length' | 'error';
  usage?: { promptTokens, completionTokens, totalTokens };
}
```

### Request Flow

```
User Input
    ↓
AITerminal Component (AITerminal.tsx)
    ↓
router.sendMessage(AIMessageOptions)
    ↓
AIProviderRouter.sendMessage()
    ├─ Try primary provider
    ├─ On success → Return response immediately
    ├─ On retryable error → Try fallback providers
    └─ On non-retryable error → Throw immediately
```

