## 6. QUICK START FOR YOUR FEATURE

To integrate AI into any feature:

```typescript
import { createDefaultRouter } from '@/services/ai/providerRouter';

export async function myFeatureUsingAI(userPrompt: string) {
  const router = createDefaultRouter();

  // Check if any provider is configured
  const configured = router.getConfiguredProviders();
  if (configured.length === 0) {
    throw new Error('No AI provider configured');
  }

  // Send message (with automatic fallback)
  const response = await router.sendMessage({
    prompt: userPrompt,
    systemPrompt: "You are a helpful assistant",
    temperature: 0.7,
    stream: true,
    onChunk: (chunk) => console.log(chunk),
  });

  return {
    answer: response.content,
    provider: response.provider,  // Track which provider answered
    model: response.model,
    tokens: response.usage,
  };
}
```

